import type { CashVoucherKind } from '../components/kt/CashVoucherList';

/** Fallback when registry API unavailable — prefer `useVoucherRegistry` / registry API. */
export type LedgerKind = 'Accounting' | 'Warehouse';

export interface CashVoucherRegistryEntry {
  voucherTypeCode: string;
  ledgerKind: LedgerKind;
}

export const CASH_VOUCHER_REGISTRY: Record<CashVoucherKind, CashVoucherRegistryEntry> = {
  receipt: { voucherTypeCode: 'phieu-thu', ledgerKind: 'Accounting' },
  payment: { voucherTypeCode: 'phieu-chi', ledgerKind: 'Accounting' },
};

export function getCashVoucherLedgerKind(kind: CashVoucherKind): LedgerKind {
  return CASH_VOUCHER_REGISTRY[kind].ledgerKind;
}
