const PATH_SHELL_PREFIXES: { prefix: string; shellId: CashVoucherShellId }[] = [
  { prefix: '/kt/bao-co', shellId: 'giay-bao-co' },
  { prefix: '/kt/bao-no', shellId: 'giay-bao-no' },
  { prefix: '/kt/unc', shellId: 'uy-nhiem-chi' },
  { prefix: '/kt/phieu-thu', shellId: 'phieu-thu' },
  { prefix: '/kt/pt', shellId: 'phieu-thu' },
  { prefix: '/kt/phieu-chi', shellId: 'phieu-chi' },
  { prefix: '/kt/pc', shellId: 'phieu-chi' },
];

export function getCashVoucherShellProfile(shellId: CashVoucherShellId): CashVoucherShellProfile {
  return CASH_VOUCHER_SHELL_PROFILES[shellId];
}

export function resolveCashVoucherShellFromPath(pathname: string): CashVoucherShellProfile | null {
  const path = pathname.split('?')[0] ?? pathname;
  for (const { prefix, shellId } of PATH_SHELL_PREFIXES) {
    if (path === prefix || path.startsWith(`${prefix}/`)) {
      return CASH_VOUCHER_SHELL_PROFILES[shellId];
    }
  }
  return null;
}

export function defaultShellIdForKind(kind: CashVoucherKind): CashVoucherShellId {
  return kind === 'receipt' ? 'phieu-thu' : 'phieu-chi';
}
